from collections import deque

def solve(grid: list[list[int]], k: int) -> int:
    m = len(grid)
    if m == 0:
        return 0
    n = len(grid[0])
    visited = [[False for _ in range(n)] for _ in range(m)]
    count = 0

    for i in range(m):
        for j in range(n):
            if grid[i][j] != 0 and not visited[i][j]:
                queue = deque()
                queue.append((i, j))
                visited[i][j] = True
                sum_val = grid[i][j]
                while queue:
                    x, y = queue.popleft()
                    for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                        nx = x + dx
                        ny = y + dy
                        if 0 <= nx < m and 0 <= ny < n and not visited[nx][ny] and grid[nx][ny] != 0:
                            visited[nx][ny] = True
                            sum_val += grid[nx][ny]
                            queue.append((nx, ny))
                if sum_val % k == 0:
                    count += 1
    return count
